1	//
2	//  CoreDataController.m
3	//  ContactManager
4	//
5	//  Created by Scott Densmore on 6/21/11.
6	//  Copyright 2011 Scott Densmore. All rights reserved.
7	//
8	
9	#import "CoreDataController.h"
10	#import "CoreDataControllerDelegate.h"
11	
12	@interface CoreDataController()
13	
14	@property (nonatomic, readwrite, strong, nullable) NSPersistentContainer *persistentContainer;
15	@property (nonatomic, readwrite, strong, nullable) NSManagedObjectModel *managedObjectModel;
16	@property (nonatomic, strong, nullable) NSString *initialType;
17	@property (nonatomic, strong, nullable) NSString *appSupportName;
18	@property (nonatomic, strong, nullable) NSString *modelName;
19	@property (nonatomic, strong, nullable) NSString *dataStoreName;
20	
21	@end
22	
23	@implementation CoreDataController
24	#pragma mark - Memory Management
25	
26	- (instancetype)init 
27	{
28	    return [self initWithInitialType:NSInMemoryStoreType modelName:nil applicationSupportName:nil dataStoreName:nil];
29	}
30	
31	- (instancetype)initWithModelName:(NSString *)theModelName applicationSupportName:(nullable NSString *)theApplicationSupportName dataStoreName:(nullable NSString *)theDataStoreName
32	{
33	    return [self initWithInitialType:NSXMLStoreType modelName:theModelName applicationSupportName:theApplicationSupportName  dataStoreName:theDataStoreName];
34	}
35	
36	- (instancetype)initWithInitialType:(NSString *)type modelName:(NSString *)theModelName applicationSupportName:(nullable NSString *)theApplicationSupportName dataStoreName:(nullable NSString *)theDataStoreName
37	{
38	    NSParameterAssert(theModelName != nil);
39	    
40	    self = [super init];
41		if (self) {
42			_initialType = type;
43	        _modelName = theModelName;
44	        if (![_initialType isEqualToString:NSInMemoryStoreType]) {
45	            NSParameterAssert(theApplicationSupportName != nil);
46	            NSParameterAssert(theDataStoreName != nil);
47	            _appSupportName = theApplicationSupportName;
48	            _dataStoreName = theDataStoreName;
49	        }
50		}
51		return self;
52	}
53	
54	
55	#pragma mark - Accesssors
56	
57	- (NSString *)applicationSupportFolder 
58	{
59	    NSArray *paths = NSSearchPathForDirectoriesInDomains(NSApplicationSupportDirectory, NSUserDomainMask, YES);
60	    NSString *basePath = ([paths count] > 0) ? paths[0] : NSTemporaryDirectory();
61		return [basePath stringByAppendingPathComponent:_appSupportName];
62	}
63	
64	- (NSManagedObjectModel *)managedObjectModel 
65	{
66	    if (_managedObjectModel != nil) {
67	        return _managedObjectModel;
68	    }
69		
70		NSURL *modelUrl = [[NSBundle mainBundle] URLForResource:[_modelName stringByDeletingPathExtension] withExtension:[_modelName pathExtension]];
71	    _managedObjectModel = [[NSManagedObjectModel alloc] initWithContentsOfURL:modelUrl];
72	    return _managedObjectModel;
73	}
74	
75	- (NSPersistentContainer *)persistentContainer
76	{
77	    if (_persistentContainer != nil) {
78	        return _persistentContainer;
79	    }
80	    
81	    NSString *containerName = [_modelName stringByDeletingPathExtension];
82	    _persistentContainer = [[NSPersistentContainer alloc] initWithName:containerName managedObjectModel:[self managedObjectModel]];
83	    
84	    NSPersistentStoreDescription *storeDescription;
85	    if ([_initialType isEqualToString:NSInMemoryStoreType]) {
86	        storeDescription = [NSPersistentStoreDescription persistentStoreDescriptionWithURL:[NSURL fileURLWithPath:@"/dev/null"]];
87	    } else {
88	        NSFileManager *fileManager = [NSFileManager defaultManager];
89	        NSString *applicationSupportFolder = [self applicationSupportFolder];
90	        NSError *error = nil;
91	        if (![fileManager fileExistsAtPath:applicationSupportFolder isDirectory:NULL]) {
92	            if (![fileManager createDirectoryAtPath:applicationSupportFolder withIntermediateDirectories:NO attributes:nil error:&error]) {
93	                NSAssert(NO, ([NSString stringWithFormat:@"Failed to create App Support directory %@ : %@", applicationSupportFolder, error]));
94	                LOG(@"Error creating application support directory at %@ : %@", applicationSupportFolder, error);
95	                _persistentContainer = nil;
96	                return nil;
97	            }
98	        }
99	        
100	        NSURL *url = [NSURL fileURLWithPath:[applicationSupportFolder stringByAppendingPathComponent:_dataStoreName]];
101	        storeDescription = [NSPersistentStoreDescription persistentStoreDescriptionWithURL:url];
102	    }
103	    
104	    storeDescription.type = _initialType;
105	    storeDescription.shouldMigrateStoreAutomatically = YES;
106	    storeDescription.shouldInferMappingModelAutomatically = YES;
107	    
108	    _persistentContainer.persistentStoreDescriptions = @[storeDescription];
109	    
110	    dispatch_semaphore_t sem = dispatch_semaphore_create(0);
111	    __block NSError *loadError = nil;
112	    
113	    [_persistentContainer loadPersistentStoresWithCompletionHandler:^(NSPersistentStoreDescription *description, NSError *error) {
114	        if (error) {
115	            loadError = error;
116	        }
117	        dispatch_semaphore_signal(sem);
118	    }];
119	    
120	    dispatch_semaphore_wait(sem, DISPATCH_TIME_FOREVER);
121	    
122	    if (loadError) {
123	        if ([loadError code] == 134100) {
124	            if ([[self delegate] respondsToSelector:@selector(coreDataController:encounteredIncorrectModelWithVersionIdentifiers:)]) {
125	                NSError *metadataError = nil;
126	                NSDictionary *metadata = [NSPersistentStoreCoordinator metadataForPersistentStoreOfType:self.initialType URL:storeDescription.URL options:nil error:&metadataError];
127	                if (metadata) {
128	                    [[self delegate] coreDataController:self encounteredIncorrectModelWithVersionIdentifiers:metadata[NSStoreModelVersionIdentifiersKey]];
129	                } else {
130	                    LOG(@"Error retrieving metadata for version identifiers: %@", metadataError);
131	                }
132	            }
133	        } else {
134	            [[NSApplication sharedApplication] presentError:loadError];
135	        }
136	        _persistentContainer = nil;
137	        return nil;
138	    }
139	    
140	    return _persistentContainer;
141	}
142	
143	- (NSPersistentStoreCoordinator *)persistentStoreCoordinator
144	{
145	    return self.persistentContainer.persistentStoreCoordinator;
146	}
147	
148	- (NSManagedObjectContext *)managedObjectContext
149	{
150	    return self.persistentContainer.viewContext;
151	}
152	
153	- (BOOL)save:(NSError **)error
154	{
155	    BOOL reply = YES;
156		NSManagedObjectContext *moc = [self managedObjectContext];
157		if (moc != nil) {
158			if ([moc commitEditing]) {
159				if ([moc hasChanges]) {
160	                return [moc save:error];
161	            }
162	        }
163		}
164		return reply;
165	}
166	
167	@end
