//
//  Contact.swift
//  ContactManager
//
//  The SwiftData model backing a single contact. Replaces the legacy
//  Core Data `Contact` NSManagedObject.
//

import Foundation
import SwiftData

@Model
final class Contact {
    var firstName: String
    var lastName: String
    var emailAddress: String
    var phoneNumber: String
    var createdAt: Date

    init(
        firstName: String = "",
        lastName: String = "",
        emailAddress: String = "",
        phoneNumber: String = "",
        createdAt: Date = .now
    ) {
        self.firstName = firstName
        self.lastName = lastName
        self.emailAddress = emailAddress
        self.phoneNumber = phoneNumber
        self.createdAt = createdAt
    }
}

extension Contact {
    /// Human-readable name, falling back to a placeholder for brand-new contacts.
    var fullName: String {
        let name = [firstName, lastName]
            .map { $0.trimmingCharacters(in: .whitespaces) }
            .filter { !$0.isEmpty }
            .joined(separator: " ")
        return name.isEmpty ? "New Contact" : name
    }

    /// One or two uppercase letters used for the avatar placeholder.
    var initials: String {
        let first = firstName.trimmingCharacters(in: .whitespaces).first.map(String.init) ?? ""
        let last = lastName.trimmingCharacters(in: .whitespaces).first.map(String.init) ?? ""
        let combined = (first + last).uppercased()
        return combined.isEmpty ? "#" : combined
    }

    /// Lowercased key used to sort contacts by last name, then first name.
    var sortKey: String {
        let last = lastName.trimmingCharacters(in: .whitespaces)
        let primary = last.isEmpty ? firstName : last
        return primary.trimmingCharacters(in: .whitespaces).lowercased()
    }
}

//
//  ContactQuery.swift
//  ContactManager
//
//  Pure, testable helpers for filtering and sorting contacts. Keeping this
//  logic out of the views makes it straightforward to unit test.
//

import Foundation

enum ContactQuery {
    /// Sorts contacts by last name, then first name, case-insensitively.
    static func sorted(_ contacts: [Contact]) -> [Contact] {
        contacts.sorted { lhs, rhs in
            if lhs.sortKey != rhs.sortKey {
                return lhs.sortKey < rhs.sortKey
            }
            return lhs.firstName.lowercased() < rhs.firstName.lowercased()
        }
    }

    /// Filters contacts whose name, email, or phone contains the query.
    /// An empty query returns every contact unchanged.
    static func filtered(_ contacts: [Contact], matching query: String) -> [Contact] {
        let needle = query.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        guard !needle.isEmpty else { return contacts }

        return contacts.filter { contact in
            contact.fullName.lowercased().contains(needle)
                || contact.emailAddress.lowercased().contains(needle)
                || contact.phoneNumber.lowercased().contains(needle)
        }
    }
}

