4	//
5	//  Pure, testable helpers for filtering and sorting contacts. Keeping this
6	//  logic out of the views makes it straightforward to unit test.
7	//
8	
9	import Foundation
10	
11	enum ContactQuery {
12	    /// Sorts contacts by last name, then first name, case-insensitively.
13	    static func sorted(_ contacts: [Contact]) -> [Contact] {
14	        contacts.sorted { lhs, rhs in
15	            if lhs.sortKey != rhs.sortKey {
16	                return lhs.sortKey < rhs.sortKey
17	            }
18	            return lhs.firstName.lowercased() < rhs.firstName.lowercased()
19	        }
20	    }
21	
22	    /// Filters contacts whose name, email, or phone contains the query.
23	    /// An empty query returns every contact unchanged.
