    var jobTitle: String = ""

    // Postal address
    var street: String = ""
    var city: String = ""
    var state: String = ""
    var postalCode: String = ""
    var country: String = ""

    // Misc
    var birthday: Date?
    var notes: String = ""
    var createdAt: Date = Date.now

    // Labeled emails and phone numbers.
    @Relationship(deleteRule: .cascade, inverse: \ContactField.contact)
    var fields: [ContactField]

    init(
        firstName: String = "",
        lastName: String = "",
        company: String = "",
        jobTitle: String = "",
        street: String = "",
        city: String = "",
        state: String = "",
        postalCode: String = "",
        country: String = "",
        birthday: Date? = nil,
        notes: String = "",
        createdAt: Date = .now
    ) {
        self.firstName = firstName
        self.lastName = lastName
        self.company = company
        self.jobTitle = jobTitle
        self.street = street
        self.city = city
        self.state = state
        self.postalCode = postalCode
        self.country = country
        self.birthday = birthday
        self.notes = notes
        self.createdAt = createdAt
        self.fields = []
    }
}

