//
//  Contact.swift
//  ContactManager
//
//  The SwiftData model backing a single contact.
//

import Foundation
import SwiftData

@Model
final class Contact {
    // Identity
    var firstName: String = ""
    var lastName: String = ""

    // Work
    var company: String = ""
    var jobTitle: String = ""

    // Postal address
    var street: String = ""
    var city: String = ""
    var state: String = ""
    var postalCode: String = ""
    var country: String = ""

    // Misc
    var birthday: Date?
    var notes: String = ""
    var createdAt: Date = Date.now

    /// Downscaled avatar image (JPEG). `.externalStorage` lets SwiftData keep
    /// large blobs outside the SQLite file when appropriate.
    @Attribute(.externalStorage) var photoData: Data?

    // Labeled emails and phone numbers.
    @Relationship(deleteRule: .cascade, inverse: \ContactField.contact)
    var fields: [ContactField]

    init(
        firstName: String = "",
        lastName: String = "",
        company: String = "",
        jobTitle: String = "",
        street: String = "",
        city: String = "",
        state: String = "",
        postalCode: String = "",
        country: String = "",
        birthday: Date? = nil,
        notes: String = "",
        createdAt: Date = .now
    ) {
        self.firstName = firstName
        self.lastName = lastName
        self.company = company
        self.jobTitle = jobTitle
        self.street = street
        self.city = city
        self.state = state
        self.postalCode = postalCode
        self.country = country
        self.birthday = birthday
        self.notes = notes
        self.createdAt = createdAt
        self.fields = []
    }
}

extension Contact {
    /// Human-readable name, falling back to company, then a placeholder.
    var fullName: String {
        let name = [firstName, lastName]
            .map { $0.trimmingCharacters(in: .whitespaces) }
            .filter { !$0.isEmpty }
            .joined(separator: " ")
        if !name.isEmpty { return name }
        let trimmedCompany = company.trimmingCharacters(in: .whitespaces)
        return trimmedCompany.isEmpty ? "New Contact" : trimmedCompany
    }

    /// One or two uppercase letters used for the avatar placeholder.
    var initials: String {
        let first = firstName.trimmingCharacters(in: .whitespaces).first.map(String.init) ?? ""
        let last = lastName.trimmingCharacters(in: .whitespaces).first.map(String.init) ?? ""
        var combined = (first + last).uppercased()
        if combined.isEmpty {
            combined = company.trimmingCharacters(in: .whitespaces).first.map { String($0).uppercased() } ?? ""
        }
        return combined.isEmpty ? "#" : combined
    }

    /// Lowercased key used to sort contacts: last name, then first name, then
    /// company. Falling back to company keeps sorting/sectioning aligned with
    /// the displayed `fullName` for company-only contacts.
    var sortKey: String {
        for candidate in [lastName, firstName, company] {
            let trimmed = candidate.trimmingCharacters(in: .whitespaces)
            if !trimmed.isEmpty { return trimmed.lowercased() }
        }
        return ""
    }

    /// Lowercased first name, trimmed — used as the secondary sort key so it
    /// stays consistent with `sortKey`.
    var firstNameSortKey: String {
        firstName.trimmingCharacters(in: .whitespaces).lowercased()
    }

    /// Deterministic, launch-stable seed for the avatar tint. Derived from the
    /// persisted creation date so the color survives relaunches (unlike
    /// `hashValue`, which is per-process) and doesn't shift when the name is
    /// edited.
    var colorSeed: Int {
        Int(truncatingIfNeeded: createdAt.timeIntervalSinceReferenceDate.bitPattern)
    }

    /// Primary/secondary keys for a given sort order. The primary key also
    /// drives alphabetical section grouping.
    func sortKeys(for order: ContactSortOrder) -> (primary: String, secondary: String) {
        switch order {
        case .lastName:
            return (sortKey, firstNameSortKey)
        case .firstName:
            let first = firstNameSortKey
            return (first.isEmpty ? sortKey : first, sortKey)
        }
    }

    // MARK: - Field helpers

    var emails: [ContactField] { fields(of: .email) }
    var phones: [ContactField] { fields(of: .phone) }

    func fields(of kind: FieldKind) -> [ContactField] {
        fields
            .filter { $0.kind == kind }
            .sorted { $0.sortIndex < $1.sortIndex }
    }

    /// The first non-empty email, used as the list subtitle.
    var primaryEmail: String? {
        emails.first { !$0.value.trimmingCharacters(in: .whitespaces).isEmpty }?.value
    }

    /// The first non-empty phone number.
    var primaryPhone: String? {
        phones.first { !$0.value.trimmingCharacters(in: .whitespaces).isEmpty }?.value
    }

    /// Best available secondary line for list rows: email, then phone, then company.
    var subtitle: String? {
        if let email = primaryEmail { return email }
        if let phone = primaryPhone { return phone }
        let trimmedCompany = company.trimmingCharacters(in: .whitespaces)
        return trimmedCompany.isEmpty ? nil : trimmedCompany
    }
}

//
//  ContactManagerApp.swift
//  ContactManager
//
//  SwiftUI entry point. Replaces the legacy AppDelegate / main.m / MainMenu.xib
//  AppKit launch path.
//

import SwiftUI
import SwiftData

@main
struct ContactManagerApp: App {
    @State private var loadState: ContainerLoadState

    init() {
        _loadState = State(initialValue: Self.loadContainer())
    }

    var body: some Scene {
        WindowGroup {
            switch loadState {
            case .ready(let container):
                ContentView()
                    .modelContainer(container)
            case .testing:
                EmptyView()
            case .failed(let message):
                StoreErrorView(message: message) {
                    loadState = Self.loadContainer(resettingStore: true)
                }
            }
        }
        .commands {
            CommandGroup(replacing: .newItem) {
                Button("New Contact") {
                    NotificationCenter.default.post(name: .newContactRequested, object: nil)
                }
                .keyboardShortcut("n", modifiers: .command)
            }
        }
    }

    // MARK: - Container loading

    private static func loadContainer(resettingStore: Bool = false) -> ContainerLoadState {
        // When hosting the unit tests, skip building the app's model container
        // entirely so the test target owns the only container in the process.
        let isTesting = ProcessInfo.processInfo.environment["XCTestConfigurationFilePath"] != nil
            || NSClassFromString("XCTestCase") != nil
        if isTesting { return .testing }

        if resettingStore {
            deleteDefaultStore()
        }

        do {
            let container = try ModelContainer(for: Contact.self, ContactField.self)
            do {
                try SampleData.seedIfNeeded(container.mainContext)
            } catch {
                // Seeding is best-effort; a failure here shouldn't block launch.
                print("ContactManager: sample data seeding skipped — \(error)")
            }
            return .ready(container)
        } catch {
            return .failed(error.localizedDescription)
        }
    }

    /// Removes the default SwiftData store files so a corrupt store can be
    /// recovered from without reinstalling the app.
    private static func deleteDefaultStore() {
        let fileManager = FileManager.default
        guard let support = try? fileManager.url(
            for: .applicationSupportDirectory, in: .userDomainMask,
            appropriateFor: nil, create: false
        ) else { return }

        for suffix in ["", "-wal", "-shm"] {
            try? fileManager.removeItem(at: support.appending(path: "default.store\(suffix)"))
        }
    }
}

private enum ContainerLoadState {
    case ready(ModelContainer)
    case testing
    case failed(String)
}

/// Shown when the persistent store can't be opened, offering a recovery path
/// instead of crashing the app.
private struct StoreErrorView: View {
    let message: String
    let onReset: () -> Void

    var body: some View {
        ContentUnavailableView {
            Label("Couldn't Open Your Contacts", systemImage: "externaldrive.badge.exclamationmark")
        } description: {
            Text(message)
        } actions: {
            Button("Reset Data", role: .destructive, action: onReset)
                .buttonStyle(.borderedProminent)
        }
        .frame(minWidth: 360, minHeight: 240)
    }
}

extension Notification.Name {
    /// Posted by the New Contact menu command; observed by `ContentView`.
    static let newContactRequested = Notification.Name("ContactManager.newContactRequested")
}

